import { test, expect } from '@playwright/test';

test('homepage has title and links to intro page', async ({ page }) => {
  await page.goto('https://playwright.dev/');

  // Expect a title "to contain" a substring.
  await expect(page).toHaveTitle(/Playwright/);
});

// ✅ Priority order — use the FIRST one that applies:

// 1. getByRole — matches what users and screen readers see
await page.getByRole('button', { name: 'Add to Cart' }).click();
await page.getByRole('heading', { name: 'Checkout' }).isVisible();
await page.getByRole('textbox', { name: 'Email address' }).fill('a@b.com');

// 2. getByLabel — for form fields (links input to its label)
await page.getByLabel('Password').fill('Secret123');
await page.getByLabel('Remember me').check();

// 3. getByText — for static content
await page.getByText('Welcome back, Nguyen Van A!').isVisible();
await page.getByText('Out of stock').isVisible();

// 4. getByTestId — last resort (add data-testid to the element in code)
// <div data-testid="product-skeleton">...</div>
await page.getByTestId('product-skeleton').isVisible();

// ❌ NEVER use these — they break when UI is restyled or reordered
await page.locator('.btn-primary > span:nth-child(2)').click(); // brittle CSS
await page.locator('#root > div > div:nth-child(3)').click();  // brittle path

