import { test as base, expect } from '@playwright/test';

type Fixtures = {
  authToken: string;      // worker scope — chỉ lấy token 1 lần
  apiClient: ApiClient;   // test scope — fresh instance mỗi test
  adminPage: Page;        // dùng authToken bên trong
};

export const test = base.extend<Fixtures>({
  // Worker scope: chạy 1 lần, share cho tất cả test trong worker
  authToken: [async ({}, use) => {
    const token = await fetchAuthToken('admin@test.com', 'pass');
    await use(token);
    // teardown: có thể revoke token nếu cần
  }, { scope: 'worker' }],

  // Test scope: dùng authToken (fixture khác) làm dependency
  adminPage: async ({ page, authToken }, use) => {
    await page.setExtraHTTPHeaders({ Authorization: `Bearer ${authToken}` });
    await page.goto('/admin');
    await use(page);
  },

  // Override built-in 'page' — inject cookie cho mọi test
  page: async ({ page }, use) => {
    await page.context().addCookies([{ name: 'locale', value: 'vi' }]);
    await use(page); // page bây giờ luôn có cookie locale=vi
  },
});

