// Testing a Next.js RSC page with Suspense loading state
test('product page shows skeleton then data', async ({ page }) => {
  // Slow down the API to catch the loading state
  await page.route('*/**/api/products*', async route => {
    await new Promise(r => setTimeout(r, 500)); // simulate latency
    await route.fulfill({ json: { products: mockProducts } });
  });

  await page.goto('/products');

  // Assert Suspense fallback (Skeleton) is shown first
  await expect(page.getByTestId('product-skeleton')).toBeVisible();

  // Then assert real data appears after fetch resolves
  await expect(page.getByRole('heading', { name: 'MacBook Pro' })).toBeVisible();
  await expect(page.getByTestId('product-skeleton')).not.toBeVisible();
});

// Testing a Server Action (form submit)
test('create product via Server Action', async ({ page }) => {
  await page.goto('/products/new');
  await page.getByLabel('Product Name').fill('New Item');
  await page.getByLabel('Price').fill('99.99');

  // Intercept the Server Action POST request
  const actionRequest = page.waitForRequest(r => r.url().includes('/products/new'));
  await page.getByRole('button', { name: 'Create' }).click();
  await actionRequest;

  // Assert redirect to product list after successful creation
  await page.waitForURL('/products');
  await expect(page.getByText('New Item')).toBeVisible();
});

