// global-setup.ts — login once, save state
async function globalSetup() {
  const browser = await chromium.launch();

  // Save regular user session
  const userPage = await browser.newPage();
  await userPage.goto('/login');
  await userPage.getByLabel('Email').fill('user@test.com');
  await userPage.getByLabel('Password').fill('secret');
  await userPage.getByRole('button', { name: 'Login' }).click();
  await userPage.waitForURL('/dashboard');
  await userPage.context().storageState({ path: 'playwright/.auth/user.json' });

  await browser.close();
}

