// ❌ Anti-patterns that cause flaky tests
test('flaky — hardcoded sleep', async ({ page }) => {
  await page.click('#submit');
  await page.waitForTimeout(2000); // ← NEVER do this — arbitrary, slow
  expect(await page.textContent('#result')).toBe('Success');
});

// ✅ Fix: use auto-retrying assertion
test('stable — auto-retry', async ({ page }) => {
  await page.click('#submit');
  await expect(page.getByText('Success')).toBeVisible(); // retries until visible
});

// ❌ Anti-pattern: test depends on previous test's data
test('flaky — order dependent', async ({ page }) => {
  await page.goto('/products'); // assumes test before created a product
  await expect(page.getByText('New Item')).toBeVisible();
});

// ✅ Fix: each test creates its own data
test('stable — self-contained', async ({ page, request }) => {
  // Create data via API (faster than UI)
  await request.post('/api/products', { data: { name: 'Test Item' } });
  await page.goto('/products');
  await expect(page.getByText('Test Item')).toBeVisible();
  // Cleanup: delete the product after test
  await request.delete('/api/products/test-item');
});

// expect.soft() — collect multiple failures in 1 run
test('dashboard metrics', async ({ page }) => {
  await page.goto('/dashboard');
  await expect.soft(page.getByTestId('revenue')).toBeVisible();    // continues even if fails
  await expect.soft(page.getByTestId('user-count')).toBeVisible(); // continues
  await expect.soft(page.getByTestId('orders')).toBeVisible();     // continues
  // Report ALL soft failures at the end
});
